css:
.viz-inner {
  width: 100%; max-width: 580px; height: 100%;
  display: flex; flex-direction: column; justify-content: center;
}

.chart-header { margin-bottom: 16px; }
.chart-header h3 { font-size: 16px; font-weight: 600; color: var(--heading); margin-bottom: 4px; }
.chart-header p { font-size: 12px; color: var(--text-muted); }

.chart-bars {
  flex: 1; display: flex; align-items: flex-end; gap: 4px;
  height: 260px; padding-bottom: 28px; position: relative;
}

.chart-bars::before {
  content: ''; position: absolute; left: 0; right: 0; bottom: 28px;
  height: 1px; background: var(--border);
}

.bar-group {
  flex: 1; display: flex; flex-direction: column; align-items: center;
  gap: 6px; position: relative; height: 100%; justify-content: flex-end;
}

.bar {
  width: 70%; max-width: 48px; border-radius: 4px 4px 0 0;
  background: var(--accent, #ea580c); transition: all 0.6s cubic-bezier(0.4, 0, 0.2, 1);
  position: relative; min-height: 2px; cursor: pointer;
}

.bar:hover { filter: brightness(1.2); }

.bar-value {
  position: absolute; top: -20px; left: 50%; transform: translateX(-50%);
  font-size: 11px; font-weight: 600; color: var(--accent-lt, #fb923c);
  opacity: 0; transition: opacity 0.2s; white-space: nowrap;
}

.bar:hover .bar-value { opacity: 1; }

.bar-label {
  font-size: 10px; color: var(--text-muted); text-align: center;
  white-space: nowrap; overflow: hidden; text-overflow: ellipsis; max-width: 100%;
}

.chart-insight {
  margin-top: 16px; padding: 14px 16px;
  background: var(--bg-secondary); border: 1px solid var(--border);
  border-radius: 8px; font-size: 13px; color: var(--text); line-height: 1.6;
  transition: opacity 0.3s;
}

.chart-insight strong { color: var(--accent-lt, #fb923c); font-weight: 600; }

